local FuncCondition = {
    BuildingLv = 1,  -- 建筑等级
    MissionId = 2,   -- 已通关的关卡ID
    VipLevel = 3,    -- VIP等级
    GuideId = 4,     -- 完成新手指引
    QuestStory = 5,  -- 完成剧情任务
    FinishStoryEvent = 6,  -- 完成剧情某个事件
}
local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxFuncOpenCtrl:LxBaseCtrl
local LxFuncOpenCtrl = classX("LxFuncOpenCtrl", LxBaseCtrl)

function LxFuncOpenCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxFuncOpenCtrl:Dispose()

    LxBaseCtrl.Dispose(self)
