---@return V_FunctionMgrRef
function LxFuncOpenCtrl:GetFunctionMgrRefByRefId(refId)
    return GameTable.FunctionMgrRef[refId]
end

function LxFuncOpenCtrl:GetFunctionNameByRefId(refId)
    local ref = self:GetFunctionMgrRefByRefId(refId)
    return ref and I18nText(ref.name) or ""
end

function LxFuncOpenCtrl:IsFuncShow(funcRefId)
    if funcRefId == 0 then return true end
    local isShow = self:InnerCheckShow(funcRefId)
    local openingId = ModuleCenter.FuncOpen:GetOpeningId()
    if openingId == funcRefId then
        return false
    end
    local isWait = ModuleCenter.FuncOpen:CheckIsWait(funcRefId)
    if isWait then
        return false
    end
    if isShow then return true end
    return self:InnerCheckOpen(funcRefId)
end

function LxFuncOpenCtrl:IsFuncOpen(funcRefId, tipsType)
    if funcRefId == 0 then return true end
    local isOpen = self:InnerCheckOpen(funcRefId)
    if not isOpen and tipsType then
        self:ShowNotOpenTips(tipsType, funcRefId)
    end
    return isOpen
end

function LxFuncOpenCtrl:GetShowAndOpen(funcRefId)
    local isShow = self:InnerCheckShow(funcRefId)
    local isOpen = self:InnerCheckOpen(funcRefId)
    return { isShow = isShow, isOpen = isOpen }
end

function LxFuncOpenCtrl:InnerCheckShow(funcRefId)
    local ref = self:GetFunctionMgrRefByRefId(funcRefId)
    if not ref then
        if LOG_INFO_ENABLED then
            printError("FuncOpen", "不存在功能开启id="..tostring(funcRefId))
        end
        return true
    end
    return ref.show == 1
end

function LxFuncOpenCtrl:InnerCheckOpen(funcRefId)
    local ref = self:GetFunctionMgrRefByRefId(funcRefId)
    if not ref then
        if LOG_INFO_ENABLED then
            printError("FuncOpen", "不存在功能开启id="..tostring(funcRefId))
        end
        return true
    end
    local open = self:CheckConditions(ref.open)
    if not open then
        open = self:CheckConditions(ref.otherOpen, true)
    end
    return open
end

function LxFuncOpenCtrl:ShowNotOpenTips(tipsType, funcRefId)
    if tipsType == FuncOpenTipsEnum.Normal then
        ShowSysMsg(self:GetNotOpenTips(funcRefId))
    end
end

function LxFuncOpenCtrl:GetNotOpenTips(funcRefId)
    local refData = self:GetFunctionMgrRefByRefId(funcRefId)
    local tips = ""
    if refData.open then
        local a1 = 0
        local conditionParams = string.split(refData.open[1], "=")
        local conditionType = tonumber(conditionParams[1])
        if conditionType == FuncCondition.BuildingLv then -->=建筑等级
            local cdtLv = tonumber(conditionParams[3]) or 0
            a1 = cdtLv
        else
            local cdtLv = tonumber(conditionParams[2]) or 0
            a1 = cdtLv
        end
        tips = I18nText(refData.openTip, a1)
    end
    return tips
end

function LxFuncOpenCtrl:CheckConditions(conditionStrList, isNotAllowEmpty)
    local bMatch = false
    for k,v in ipairs(conditionStrList or {}) do
        local arr = string.split(v,"=")
        if arr and #arr >= 2 then
            if not self:CheckCondition(arr) then return false end
            bMatch = true
        end
    end
    if isNotAllowEmpty then
        return bMatch
    end
    return true
end

function LxFuncOpenCtrl:CheckCondition(conditionParams)
    local conditionType = tonumber(conditionParams[1])
    if conditionType == FuncCondition.BuildingLv then -->=建筑等级
        local buildingId = tonumber(conditionParams[2]) or 0
        local cdtLv = tonumber(conditionParams[3]) or 0
        local lv = ModuleCenter.Building:GetBuildingLvl(buildingId)
        return lv >= cdtLv
    elseif conditionType == FuncCondition.MissionId then -->=已通关的关卡ID
        local curLv = ModuleCenter.FightIdle:GetCompleteMission()
        local cdtLv = tonumber(conditionParams[2]) or 0
        return curLv >= cdtLv
    elseif conditionType == FuncCondition.VipLevel then -->=VIP等级
        local vipLv = ModuleCenter.Role:GetRoleVipLevel()
        local cdtLv = tonumber(conditionParams[2]) or 0
        return vipLv >= cdtLv
    elseif conditionType == FuncCondition.GuideId then --完成新手指引
        local cdtId = tonumber(conditionParams[2]) or 0
        local isEnd = CtrlCenter.Story:StoryTriggerIsEnd(cdtId)
        return isEnd
    elseif conditionType == FuncCondition.QuestStory then --完成剧情章节
        local cdtRefId = tonumber(conditionParams[2]) or 0
        local isFinish = CtrlCenter.Quest:CheckChapterIdFinish(cdtRefId)
        return isFinish
    elseif conditionType == FuncCondition.FinishStoryEvent then
        local cdtRefId = tonumber(conditionParams[2]) or 0
        local isEnd = CtrlCenter.Story:StoryEventIsEnd(cdtRefId)
        return isEnd
    --elseif conditionType == 6 then --创角第N天的0点开启
    --    local createRoleTime = ModuleCenter.Role:GetRoleRegTime()
    --    local diffTime = LxUtil.DiffZeroTime(createRoleTime, LxUtil.OSTime())
    --    local cdtDay = tonumber(conditionParams[2]) or 0
    --    --转成时间计算 ，不用理会跨年，跨月的问题
    --    local cdtTime = (cdtDay - 1) * 86400
    --    return diffTime >= cdtTime
    --elseif conditionType == 7 then --开服第N天的0点开启
    --    local openTime = math.floor((ModuleCenter.Login:GetLoginServer().openTime or 0)/ 1000)
    --    local diffTime = LxUtil.DiffZeroTime(openTime, LxUtil.OSTime())
    --    local cdtDay = tonumber(conditionParams[2]) or 0
    --    --转成时间计算 ，不用理会跨年，跨月的问题
    --    local cdtTime = (cdtDay - 1) * 86400
    --    return diffTime >= cdtTime
    end
    return true
end

function LxFuncOpenCtrl:GetConditionTipsList(conditionStrList)
    local ret = {}
    for k,v in ipairs(conditionStrList or {}) do
        local arr = string.split(v,"=")
        if arr and #arr >= 2 then
            local str = self:GetConditionTips(arr)
            if not string.isempty(str) then
                table.insert(ret, str)
            end
        end
    end
    return ret
end

function LxFuncOpenCtrl:GetConditionTips(conditionParams)
    local conditionType = tonumber(conditionParams[1])
    if conditionType == 1 then
        local cdtLv = tonumber(conditionParams[2]) or 0
        return string.replace(I18nText(4401), cdtLv)
    end
end

---@return V_FunctionMgrRef[]
function LxFuncOpenCtrl:GetCityEnterFuncDatas()
    local datas = self._mainUiFuncDatas
    if not datas then
        datas = {}
        for k,v in pairs(GameTable.FunctionMgrRef) do
            if v.cityEnter > 0 then
                table.insert(datas, v)
            end
        end
        table.sort(datas ,function(a, b)
            return a.sort < b.sort
        end)
        self._mainUiFuncDatas = datas
    end
    return datas
end

