function LxFuncOpenCtrl:DoSpecialJump(funcId)
    if funcId == FuncOpnIdConst.Guild then
        CtrlCenter.Guild:OpenGuild()
        return
    end

    if funcId == FuncOpnIdConst.Role then
        CtrlCenter.Role:OpenRoleInfo()
        return
    end

    if funcId == FuncOpnIdConst.Equip then
        CtrlCenter.Equip:OpenEquipUI()
        return
    end
    if funcId == FuncOpnIdConst.GuildDonate then
        CtrlCenter.Guild:OpenGuildDonate()
        return
    end
end

function LxFuncOpenCtrl:GetFuncId2UiData(funcId)
    return _FuncIdToUiNames[funcId]
end

function LxFuncOpenCtrl:JumpTo(funcId, skipValidOpen,jumpParams)
    local funcData = self:GetFuncId2UiData(funcId)
    if not funcData then
        if LOG_INFO_ENABLED then
            printError("funcOpen", "jump id not support , id = %s", tostring(funcId))
        end
        return
    end

    if funcData.isSpecial then
        self:DoSpecialJump(funcId)
        return
    end

    if not skipValidOpen then
        if not CtrlCenter.FuncOpen:IsFuncOpen(funcId, FuncOpenTipsEnum.Normal) then
            return
        end
    end

    local uiName = funcData.uiName
    if string.isempty(uiName) then return end

    if funcData.params then --merge
        if jumpParams then
            for key, value in pairs(jumpParams) do
                funcData.params[key] = value
            end
        end
    else
        funcData.params = jumpParams
    end
    ShowPanel(uiName, funcData.params)
    return true
end

---@param cityEnter number
--- 1：标识要显示在底部菜单栏
--- 2：标识要显示在底部右侧的菜单栏
--- 3：下方背包处更多打开的菜单
---@return V_FunctionMgrRef[]
function LxFuncOpenCtrl:GetMainUIFuncsByType(cityEnter)
    if not self._mainUiFuncTypeDatas then
        self._mainUiFuncTypeDatas = {}
    end
    local datas = self._mainUiFuncTypeDatas[cityEnter]
    if not datas then
        datas = {}
        local mainUiFuncDatas = self:GetCityEnterFuncDatas()
        for i,v in ipairs(mainUiFuncDatas) do
            if v.cityEnter == cityEnter then
                table.insert(datas,v)
            end
        end
    end
    return datas
end

return LxFuncOpenCtrl